#!/bin/bash
docker exec shared-redis-6380 redis-cli -h 192.168.1.50 -p 6380 -n 7 LPUSH agent:frontend:inbox "{\"issue_id\":\"login-flow-debug\",\"from\":\"backend\",\"to\":\"frontend\",\"kind\":\"retest_request\",\"summary\":\"Test credentials generated and ready\",\"details\":{\"credentials\":{\"username\":\"testuser_frontend\",\"password\":\"TestPass123!\"},\"contract_notes\":{\"login\":\"Backend returns { 'success': true, 'data': { 'access_token': '...', 'refresh_token': '...', 'user': {...} } }\",\"user_status\":\"Backend returns { 'success': true, 'data': { 'user': {...} } }\"}},\"next_action_requested\":\"Execute end-to-end retest using the provided credentials.\",\"timestamp\":\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\"}"

docker exec shared-redis-6380 redis-cli -h 192.168.1.50 -p 6380 -n 7 SET agent:issue:login-flow-debug:state "{\"issue_id\":\"login-flow-debug\",\"status\":\"active\",\"owner\":\"frontend\",\"current_phase\":\"retest\",\"frontend_status\":\"working\",\"backend_status\":\"working\",\"latest_frontend_summary\":\"Frontend parsing fix applied. Need test credentials.\",\"latest_backend_summary\":\"Created testuser_frontend and sent credentials\",\"current_blocker\":\"\",\"next_action_for_frontend\":\"Retest end-to-end login flow using test credentials\",\"next_action_for_backend\":\"Wait for frontend test results\",\"canonical_routes\":{\"login\":\"/form/api/v1/auth/login\",\"user_status\":\"/form/api/v1/user/status\",\"refresh\":\"/form/api/v1/auth/refresh\",\"logout\":\"/form/api/v1/auth/logout\"},\"auth_contract\":{\"login_response_shape\":\"{success: true, data: {access_token, refresh_token, user}}\",\"status_response_shape\":\"{success: true, data: {user}}\",\"auth_mechanism\":\"Bearer Token via Authorization Header\"},\"last_updated_by\":\"backend\",\"last_updated_at\":\"$(date -u +%Y-%m-%dT%H:%M:%SZ)\"}"

docker exec shared-redis-6380 redis-cli -h 192.168.1.50 -p 6380 -n 7 SET agent:backend:heartbeat "$(date -u +%Y-%m-%dT%H:%M:%SZ)"
